cd /Users/yin/PycharmProjects/AIagent

# Add topic tags to CV-深度学习笔记/01-PyTorch基础-土堆 files
for f in CV-深度学习笔记/01-PyTorch基础-土堆/*.md; do
  basename=$(basename "$f" .md)
  topic=""
  case "$basename" in
    *卷积*) topic="CNN, 卷积" ;;
    *池化*) topic="CNN, 池化" ;;
    *激活*) topic="激活函数" ;;
    *线性*) topic="线性层" ;;
    *损失*) topic="损失函数, 训练" ;;
    *优化*) topic="优化器, 训练" ;;
    *模型*训练*) topic="训练流程" ;;
    *模型*验证*) topic="验证" ;;
    *模型*保存*|*模型*读取*) topic="模型管理" ;;
    *模型*使用*|*模型*修改*) topic="模型操作" ;;
    *GPU*) topic="GPU, 加速" ;;
    *Dataloader*|*加载数据*) topic="数据加载" ;;
    *Transforms*) topic="数据变换" ;;
    *torchvision*) topic="数据集" ;;
    *nn.Module*) topic="神经网络" ;;
    *Sequential*) topic="网络搭建" ;;
    *Tensorboard*) topic="可视化" ;;
    *Python*) topic="Python基础" ;;
    *安装*) topic="环境配置" ;;
    *配置*) topic="环境配置" ;;
    *开源*) topic="参考资源" ;;
    *) topic="PyTorch基础" ;;
  esac
  if [ -n "$topic" ]; then
    # Append topic to existing tags line
    sed -i '' "s/tags: \[CV, Deep-Learning, PyTorch\]/tags: [CV, Deep-Learning, PyTorch, $topic]/" "$f"
  fi
done

echo "Done adding topic tags to PyTorch基础"

