cd /Users/yin/PycharmProjects/AIagent

# Add topic tags to CV-深度学习笔记/02-深度学习理论-李沐 files
for f in CV-深度学习笔记/02-深度学习理论-李沐/*.md; do
  basename=$(basename "$f" .md)
  topic=""
  case "$basename" in
    *卷积*|*填充*|*步幅*|*通道*) topic="CNN, 卷积" ;;
    *池化*) topic="CNN, 池化" ;;
    *LeNet*|*AlexNet*|*VGG*|*NiN*|*GoogLeNet*|*ResNet*) topic="经典网络, CNN" ;;
    *RNN*|*循环神经*) topic="RNN, 序列模型" ;;
    *GRU*) topic="GRU, 序列模型" ;;
    *LSTM*|*长短期*) topic="LSTM, 序列模型" ;;
    *双向*) topic="Bi-RNN, 序列模型" ;;
    *注意力*|*自注意力*) topic="注意力机制, Transformer" ;;
    *Transformer*) topic="Transformer" ;;
    *BERT*) topic="预训练模型, BERT" ;;
    *序列模型*|*文本预处理*|*语言模型*) topic="NLP, 序列模型" ;;
    *检测*|*锚框*|*SSD*|*R-CNN*|*YOLO*) topic="目标检测" ;;
    *分割*|*FCN*|*转置卷积*) topic="语义分割" ;;
    *样式迁移*) topic="风格迁移" ;;
    *分布式*|*多GPU*|*单机多卡*) topic="分布式训练" ;;
    *GPU*|*TPU*|*CPU*|*硬件*) topic="硬件" ;;
    *批量归一化*) topic="BatchNorm, 训练技巧" ;;
    *数据增广*) topic="数据增强" ;;
    *微调*) topic="微调" ;;
    *优化算法*) topic="优化器" ;;
    *正则*|*权重衰退*|*丢弃*|*过拟合*|*欠拟合*) topic="正则化" ;;
    *模型选择*) topic="模型评估" ;;
    *Kaggle*|*竞赛*) topic="实战" ;;
    *深度学习介绍*) topic="概述" ;;
    *线性代数*|*矩阵*|*自动求导*) topic="数学基础" ;;
    *线性回归*|*Softmax*|*多层感知机*) topic="基础模型" ;;
    *seq2seq*|*编码器*|*解码器*) topic="Seq2Seq" ;;
    *束搜索*) topic="解码策略" ;;
    *语言模型*) topic="语言模型" ;;
    *数值稳定*|*激活函数*) topic="训练技巧" ;;
    *) topic="深度学习理论" ;;
  esac
  if [ -n "$topic" ]; then
    sed -i '' "s/tags: \[CV, Deep-Learning, PyTorch\]/tags: [CV, Deep-Learning, PyTorch, $topic]/" "$f"
  fi
done

echo "Done adding topic tags to 李沐"

